CustomField.formula:
DATE(

/* Year Logic */
VALUE(RIGHT(New_Value__c , 4))
,

/* Month Logic */
VALUE(LEFT(New_Value__c ,
FIND("/",New_Value__c ) - 1))
,

/* Day Logic */
VALUE(MID(New_Value__c ,
FIND("/",New_Value__c ) + 1,
FIND("/",New_Value__c , FIND("/",New_Value__c ) + 1) -
FIND("/",New_Value__c ) - 1
))

)
-
DATE(

/* Year Logic */
VALUE(RIGHT(Old_Value__c , 4))
,

/* Month Logic */
VALUE(LEFT(Old_Value__c ,
FIND("/",Old_Value__c ) - 1))
,

/* Day Logic */
VALUE(MID(Old_Value__c ,
FIND("/",Old_Value__c ) + 1,
FIND("/",Old_Value__c , FIND("/",Old_Value__c ) + 1) -
FIND("/",Old_Value__c ) - 1
))

)
